import { useState, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';
import axiosInstance from '../axiosConfig';
import { Link } from 'react-router-dom';

const Home = () => {
  const { user } = useAuth();
  const [tours, setTours] = useState([]);
  const [orderCount, setOrderCount] = useState(0); // 目前預設為 0

  useEffect(() => {
    const fetchData = async () => {
      try {
        const res = await axiosInstance.get('/api/tours');
        setTours(res.data);
        // 如果之後有 Order API，就在這裡 setOrderCount(resOrder.data.length);
      } catch (err) {
        console.error(err);
      }
    };
    fetchData();
  }, []);

  return (
    <div className="max-w-[420px] mx-auto bg-white min-h-screen flex flex-col">
      {/* Header */}
      <div className="p-6 flex justify-between items-center">
        <div>
          <p className="text-gray-400 text-xs">Good morning!</p>
          <h2 className="font-bold text-lg text-gray-800">Admin ({user?.username})</h2>
        </div>
        <div className="w-10 h-10 bg-gray-200 rounded-full overflow-hidden">
          <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user?.username}`} alt="avatar" />
        </div>
      </div>

      {/* 統計區塊 */}
      <div className="px-6 mb-6">
        <div className="bg-white border border-gray-100 p-5 rounded-[24px] shadow-sm flex items-center space-x-4">
          <div className="bg-yellow-100 p-3 rounded-2xl text-2xl">📋</div>
          <div>
            <p className="text-gray-400 text-xs font-bold uppercase tracking-wider">Order List</p>
            <p className="text-2xl font-black text-gray-900">{orderCount}</p> 
          </div>
        </div>
      </div>

      {/* 列表區 */}
      <div className="px-6 flex-1">
        <h3 className="font-bold text-gray-800 mb-4">View Package ({tours.length})</h3>
        {/* ... 這裡跑 tours.map 渲染清單 ... */}
      </div>

      {/* 修改後的底部按鈕 */}
      <div className="p-6 sticky bottom-0 bg-white">
        <Link 
          to="/manage-tours" 
          className="block w-full bg-emerald-500 text-white text-center font-bold py-4 rounded-2xl shadow-lg shadow-emerald-100 active:scale-95 transition"
        >
          Manage Tour Management
        </Link>
      </div>
    </div>
  );
};
export default Home;
